const Q_CHEMISTRY_2014=[{"id": "objective>Chemistry>2014>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">English</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C.R.S</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question is asking about the subject being done, and since the context is Chemistry, the answer is Chemistry.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : ELEMENTS COMPOUNDS AND MIXTURES"}, {"id": "objective>Chemistry>2014>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture is different from a compound because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a mixture is always homogeneous while a compound is not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the constituents of a compound are chemically bound together while those of a mixture are not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a mixture can be represented by a chemical formula while a compound cannot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the properties of a compound are those of its individual constituents while those of a mixture differ from its constituents</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture differs from a compound in the sense that the constituents of a compound are chemically bonded  together while those of a mixture are not.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : ELEMENTS COMPOUNDS AND MIXTURES"}, {"id": "objective>Chemistry>2014>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the percentage of sulphur in sulphur(IV) oxide?  <br/> [S=32, 0=16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">66% \t\t\t\t</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The percentage of sulphur in sulphur(IV) oxide can be calculated using the formula: (Number of atoms of sulphur x RAM of sulphur/RMM of sulphur(IV) oxide) * 100%.  <br/> The RMM of sulphur(IV) oxide (SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) = (1 x RAM of S) + (2 x RAM of O) <br/> =(1 x 32) + (2 x 16) <br/> =32 + 32 <br/> =64 <br/> Therefore, the percentage of sulphur is (1 x 32)/64 x 100% <br/> =50%</div>", "topic": "CHEMICAL COMBINATION : RELATIVE ATOMIC MASS BASED ON CARBON 12"}, {"id": "objective>Chemistry>2014>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> A gas X diffuses twice as fast as gas Y. If the relative molecular mass of X is 32, calculate the relative molecular mass of Y.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">64</div>", "<div style=\"font-family:Cambria;font-size:17px;\">128</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rate of diffusion α 1/√ M  <br/>  R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = rate of diffusion of x, R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>= rate of diffusion of Y  <br/>  R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>/R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = √ (M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>/M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>) <br/>  2/1= √ M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>/32  <br/>  M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>= 4 × 32 = 128.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2014>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a gas at 25 °C exerts a pressure of 700 mmHg. Calculate its pressure if its volume increases to 350cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at 75°C.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1430.54 mmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">467.11mmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400.00 mmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">342.53 mmHg</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This question involves the use of the combined gas law which states that the ratio of the product of pressure and volume to temperature of a system remains constant. Therefore, P1V1/T1 = P2V2/T2. Given that P1 = 700 mmHg, V1 = 200 cm^3, T1 = 25°C = 298K (converted from Celsius to Kelvin by adding 273), V2 = 350 cm^3, and T2 = 75°C = 348K, we can solve for P2 to get P2 = P1V1T2/T1V2 = (700*200*348)/(298*350) = 467.11 mmHg.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2014>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An element X has electron configuration 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> 3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>. Which of the following statements is correct about the element?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It has 5 electrons in its outermost shell.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It belongs to group II on the periodic table.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is a halogen.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It has a completely filled p-orbital.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct statement is that the element is a halogen. Reason being that it contains seven electrons in it outermost shell.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2014>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Beryllium and aluminum have similar properties because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">belong to the same group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">belong to the same period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are positioned diagonally to each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are both metals</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reason is that both elements are positioned diagonally to eachother. Hence, a diagonal relationship exist between them.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2014>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the difference in electronegativity of elements P and Q is 3.0. The bond that will be formed between them is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">co-ordinate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As the difference in electronegativity of the two element is quite high, the kind of bond that will exist between them would be ionic. The degree to which an atom attracts electrons in a chemical bond is described by electronegativity. If the difference in electronegativity is greater than 1.7, the character of the bond will be ionic. If the difference in electronegativity is between 0.4 and 1.7, the character of the bond is polar covalent. For example the electronegativity of Fluorine is 3.98 and the electronegativity  of Lithium is 0.98. They form a compound LiF(Lithium fluoride) with an ionic bond.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2014>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many protons, neutrons and electrons respectively are present in the element <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">60</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">27</span>Co? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">33,27 and 27</div>", "<div style=\"font-family:Cambria;font-size:17px;\">27,33 and 27</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60,33 and 60</div>", "<div style=\"font-family:Cambria;font-size:17px;\">27,33 and 33</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cobalt has an atomic number of 27 and weighs 60. The proton number is the atomic number which is 27 and it is the same with the electron because it is not an ion. The sum of the proton and neutron number will give the mass number. The mass number minus proton number will give the neutron number. <br/> Cobalt(Co) atomic mass =60 while <br/>  the proton/electron=27  <br/> Neutron =Mass number - Proton <br/> =60-27=33. <br/> Hence, the number of protons, neutrons and electrons are 27, 33 and 27 respectively.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2014>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The radioactive radiation used in studying the arrangement of particles in giant organic molecules is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">α-particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X-rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">β-partic1es</div>", "<div style=\"font-family:Cambria;font-size:17px;\">γ-rays</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">X-rays are used in studying the arrangement of particles in giant organic molecules. This is because X-rays have the right wavelength to interact with the electrons in the atoms and molecules, and can be diffracted to produce a diffraction pattern. This pattern can be used to determine the arrangement of atoms in a crystal or in a large molecule like a protein.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2014>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A silicon-containing ore has 92% <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">28</span>Si, 5% <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">29</span>Si and 3% <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">30</span>Si. Calculate the relative atomic mass of the silicon.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">29.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">28.11</div>", "<div style=\"font-family:Cambria;font-size:17px;\">28.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.00</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> R.A.M = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.A.M</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">28</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">92<hr size=\"1\" />100</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">29</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">5<hr size=\"1\" />100</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">30</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">3<hr size=\"1\" />100</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">28 × 92 + 29 × 5 + 30 × 3<hr size=\"1\" />100</td></tr></table></div> = 28.11</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2014>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The nitrogen obtained from air has a density higher than the one from nitrogen-containing compounds because the one from air is contaminated with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rare gases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water vapour</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The density of nitrogen obtained from air is higher than that obtained from nitrogen-containing compounds because the air contains rare gases such as Argon, Neon, Helium, Krypton, Xenon, and Radon. These gases are heavier than nitrogen and therefore increase the density of the nitrogen obtained from the air.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2014>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water is said to be temporarily hard when it contains</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ca(HCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> salts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg(HCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and CaSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> salts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> and Ca(HCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> salts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca(HCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and Mg(HCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> salts</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Temporary hardness of water is caused by the presence of dissolved bicarbonate minerals (calcium bicarbonate and magnesium bicarbonate). When dissolved, these minerals yield calcium and magnesium cations and carbonate and bicarbonate anions. They are generally removed by boiling the water.</div>", "topic": "WATER : COMPOSITION BY VOLUME"}, {"id": "objective>Chemistry>2014>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On exposure to the atmosphere, a hydrated salt loses its water of crystallization to become anhydrous. This phenomenon is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deliquescence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hygroscopy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efflorescence</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Efflorescence is the process through which hydrated salts lose all or part their water of crystallization to the atmosphere.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2014>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">16.55 g of lead(II)trioxonitrate(V) was dissolved in 100 g of distilled water at 20 °C,calculate the solubility of the solute in moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. <br/> [Pb=207,N=14, 0=16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.00g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mass of the salt (solute) = 16.55g <br/> Mass of water (solvent) = 100g <br/> Recall: Density of water = 1gcm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> ∴ The volume of 100g of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O = 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">number</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">mole</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />molar mass</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">number</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">mole</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">solute</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">16.55<hr size=\"1\" />331</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.05</td><td style=\"text-align:center;\">mole</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Solubility</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.05<hr size=\"1\" />0.1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5</td><td style=\"text-align:center;\">moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td></tr></table></div></div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2014>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dispersion of a liquid in a liquid medium will give</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a fog</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a gel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an aerosol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an emulsion</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dispersion of a liquid in a liquid medium will give an emulsion. An emulsion is a mixture of two or more liquids that are normally immiscible (unmixable or unblendable). Emulsions are part of a more general class of two-phase systems of matter called colloids.</div>", "topic": "SOLUBILITY : SUSPENSIONS AND COLLOIDS"}, {"id": "objective>Chemistry>2014>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major and most effective way of controlling pollution is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pass strict laws against it by individuals and companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">educate people on the causes and effects of pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convert chemical wastes to harmless substances before releasing them into the environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improve machinery so that the substances released from combustion are less harmful</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major and most effective way of controlling pollution is to educate people on the causes and effects of pollution.</div>", "topic": "ENVIRONMENTAL POLLUTION : SOURCES AND EFFECTS OF POLLUTANTS"}, {"id": "objective>Chemistry>2014>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basicity of CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basicity of the compound is the number of replaceable hydrogen ion in a molecule of the substance. In this case, the number of replaceable hydrogen ion is 1.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2014>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The colour of litmus in a neutral medium is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pink</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">orange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purple</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Litmus in neutral medium is purple. <br/>  <br/> purple <br/> Neutral litmus paper is purple. Litmus can also be prepared as an aqueous solution that functions similarly. Under acidic conditions, the solution is red, and under alkaline conditions, the solution is blue.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2014>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mathematical expression of pH is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></td><td style=\"text-align:center;\">1<hr size=\"1\" />H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></td><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></td><td style=\"text-align:center;\">1<hr size=\"1\" />OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></td><td style=\"text-align:center;\">OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></td></tr></table></div></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">pH is the negative logarithm of hydrogen or hydroxonium ion concentration = <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></td><td style=\"text-align:center;\">1<hr size=\"1\" />H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></td></tr></table></div></div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2014>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following salts will turn blue litmus red?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Potassium hydrogentetraoxosulphate(VI)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium trioxocarbonate(IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zinc chloride hydroxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium tetrahydroxozincate(II)</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium hydrogentetraoxosulphate(VI) is an acidic salt. Hence, it will turn blue litmus red.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2014>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + CUSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> → ZnSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> + Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>  <br/>  In the reaction above, the oxidation number of the reducing agent changes from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0 to +2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1 to +2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1 to ±3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0 to +4</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reducing agent is Zn, since its O.N changes from 0 to +2.  <br/> Note that, increase in oxidation number means oxidation, and we know that any chemical species that undergoes oxidation is a reducing agent.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2014>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> → H2<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/>  The oxidizing agent in the reaction above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidising agent is H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span>. The reason is that it loses oxygen to the reducing agent, Carbon.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2014>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the quantity of electricity in coulombs required to liberate 10 g of copper from a copper compound.  <br/> [Cu = 64, F = 96500 Cmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">30156.3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60784.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15196.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32395.5</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>+ 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> = Cu  <br/> 2F = 1 mol = 64g <br/> 2F of electricity produced 64g of Cu x Coulombs of electricity will produce 10g of Cu <br/> But 1F = 96500 coulombs <br/> Therefore <br/> 2 x 96500 coulombs of electricity produced 64g of Cu x Coulombs of electricity will produce 10g of Cu. <br/>  x = 2 × 96500 x 10/64g.  <br/> Hence 10g of Cu would require 2 × 96500 × 10/64  <br/> =193000/64 <br/> = 30156.3 Coulombs</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2014>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many faraday of electricity is required to produce 0.25 mole of copper?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.01F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.05F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00F</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since one mole of Cu is produced by 2F of electricity  <br/>  0.25mole of Cu will be produced by 0.5F.</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2014>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  Z in the diagram above represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">activation energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">free energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">entropy of reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat of reaction</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The heat of the reaction is the difference between the heat contents of the products and reactants. Z is the lettering that represents the value of the difference in heat contents.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2014>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the change in free energy of a system is -899 Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and the entropy change is 10 Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> at 25 °C, calculate the enthalpy change.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-2081 Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">-649 Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">+ 649 Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">+2081 Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">∆G = -899Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/>  <br/>  ∆S = 10Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> T = 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C = 298  <br/>  <br/>  ∆G = ∆H - T∆S  <br/>  <br/>  -899=∆H -298(10)  <br/> ∆H = -899+2980  <br/>  <br/>  x = +2081kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2014>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an equilibrium reaction, which of the following conditions indicates that maximum yield of the product will be obtained?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ΔH - TΔS = 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ΔH > TΔS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equilibrium constant is less than zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equilibrium constant is very large</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium constant is very large for maximum yield of products, meaning that K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span> is greater than one.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2014>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a chemical reaction, the change in concentration of a reactant with time is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enthalpy of reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rate of reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">order of reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">entropy of reaction</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a chemical reaction, the change in concentration of a reactant with time is referred to as the rate of reaction. The rate of reaction measures how fast the reactants are converted into products. It is usually expressed in terms of the concentration of a reactant consumed or the concentration of a product formed per unit time.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2014>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> ↔ 2CrO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span> <br/>  What happens to the reaction above when the hydrogen ion concentration is increased?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The reaction will not proceed.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium position will shift to the right.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium position will shift to the left.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">More of the products will be formed.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction above when the hydrogen ion concentration is increased the equilibrium position will shift to the left.</div>", "topic": "CHEMICAL EQUILIBRA : REVERSIBLE REACTIONS"}, {"id": "objective>Chemistry>2014>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will liberate hydrogen from dilute tetraoxosulphate(Vl) acid?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Magnesium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lead</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium is a reactive metal that can displace hydrogen from dilute acids, including tetraoxosulphate(VI) acid (also known as sulfuric acid). When magnesium reacts with the acid, it forms a salt (magnesium sulphate) and liberates hydrogen gas. The other options (copper, gold, and lead) are less reactive and cannot displace hydrogen from the acid.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>2014>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> In the diagram, the function of the concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dry the gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquefy the gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remove odour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purify the gas</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>is a drying agent. In the diagram, the function of the concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is to dry the gas</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2014>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The gas that is removed by the water in the flask is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The HCl is very soluble in water and hence it is removed by it.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2014>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fluorine does not occur in the free state in nature because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it belongs to the halogen family</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is inert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of its high reactivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is a poisonous gas</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fluorine does not occur in the free state in nature because of its high reactivity. Fluorine is the most reactive of all elements and, for that reason, it is never found in nature as free fluorine. It has a strong tendency to gain an electron to form fluoride ion (F<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>).</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2014>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the extraction of sodium from fused sodium chloride, the anode is made of platinum because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorine is formed at the anode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium does not react with platinum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine does not react with platinum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium is formed at the anode</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the extraction of sodium from fused sodium chloride, the anode is made of platinum because chlorine does not react with platinum. During the electrolysis, chlorine gas is produced at the anode and if the anode is made of a material that reacts with chlorine, it would be corroded. Platinum is a noble metal and does not react with chlorine, hence it is used as anode.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>2014>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A compound that gives a brick-red colour to a non-luminous flame is likely to contain</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sodium ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aluminium ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper ions</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A compound that gives a brick-red colour to a non-luminous flame is likely to contain calcium ions. This is based on the flame test, a procedure used in Chemistry to detect the presence of certain metal ions, based on the color the flame that appears along with the compound when heated. Calcium ions cause the flame to be brick-red.</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2014>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the electrolytic extraction of calcium from calcium chloride, the cathode is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">graphite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">platinum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">iron rods are used as the cathode in the electrolytic extraction of calcium chloride</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALINE-EARTH METALS"}, {"id": "objective>Chemistry>2014>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A few drops of NaOH solution was added to an unknown salt forming a white precipitate which is insoluble in excess solution. The cation likely present is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> is insoluble in excess NaOH. The cation likely present is Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2014>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The general formula of haloalkanes where X represents the halide is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n</span>X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n+2</span>X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n+1</span>X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n-1</span>X</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Haloalkanes are derivatives of alkanes that have one or more hydrogen atoms replaced by halogen atoms. The general formula for haloalkanes is C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n+1</span>X, where n is the number of carbon atoms, X is the halogen atom, and H is the hydrogen atom.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2014>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The IUPAC nomenclature of the compound above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3-bromo-2-chlorobutanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-chloro-2-bromobutanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-chloro-3-bromobutanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-bromo-3-chlorobutanol</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2014/2014img3.png\" style=\"position:relative;max-width:100%;\"/>  <br/>  The functional group is -OH  <br/>  <br/>  The longest continous carbon chain is 4 (butane) <br/>  <br/> We consider the longest carbonchain first, then check out for the functional groups available. We start counting from the direction of the -OH- group, Cl falls on the second carbon and Br falls on the third carbon. While naming we also take the alphabetical order into consideration. Alphabetically, Br comes before Cl so the structure above is 3-bromo-2-chlorobutanol</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2014>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The alkanol obtained from the production of soap is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glycerol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">methanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propanol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soap is made by the process of saponification, which involves the reaction of fats or oils with a base, usually sodium hydroxide. The reaction produces soap and glycerol. Therefore, the alkanol obtained from the production of soap is glycerol.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2014>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ethyne is passed through a hot tube containing organo-nickel catalyst to produce</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">polythene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">benzene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isoprene</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When ethyne (acetylene) is passed through a hot tube containing an organo-nickel catalyst, the process is called cyclotrimerization. This process results in the formation of benzene.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2014>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Due to the unstable nature of ethyne, it is stored by dissolving in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">propanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanoic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethane-1,2-diol</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Due to the unstable nature of ethyne, ethyne is stored by dissolving it in propanone.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2014>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of converting starch to ethanol is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fermentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cracking</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Through fermentation, starch is converted to ethanol. Fermentation is the slow degradation process whereby large carbohydrate molecules are broken down into smaller molecules (e.g ethanol and carbon(IV)oxide) through the agency of enzymes and microorganisms (e.g yeast or fungi)</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2014>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The polymer used in making car rear lights is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bakelite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polystyrene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">polyacrylonitrile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Perspex</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Perspex is the polymer used in making car rear lights. It is a type of acrylic plastic that is known for its transparency, weather resistance, and its ability to be shaped after it has been heated to certain temperatures.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2014>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> ↔<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></span>  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> <br/>  <br/>  The purpose of H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> in the reaction above is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maintain the solution at a constant pH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the rate of hydrolysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the rate of reverse reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the yield of products</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, H+ acts as a catalyst. A catalyst is a substance that increases the rate of a chemical reaction by reducing the energy barrier of the reaction, but it does not get consumed in the reaction. Here, H+ is facilitating the hydrolysis of the ester, thereby increasing the rate of hydrolysis.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2014>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hydrocarbon has an empirical formula CH and a vapour density of 39. Determine its molecular formula. <br/> [C=12, H=1]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>\t\t\t\t</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  <br/>  Vapour density = 39 <br/>  <br/>  Emperical formula = CH  <br/>  <br/>  Recall that: <br/>  <br/>  (Empirical formula)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span> = Molecular formular -------- (1) <br/>  <br/>  (Molar mass of empirical formula)n = (Molar mass of molecular formular) <br/>  <br/>  V.D x 2 = Molar mass -------- (3) <br/>  <br/>  From (3), the molar mass of the compound <br/>  = 39 x 2 = 78 <br/>  <br/>  From (2), (12+1)n = 78 <br/>  <br/>  13n = 78; n = 6 <br/>  <br/>  From (1) <br/>  <br/>  (CH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> = Molecular formula = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2014>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Polystyrene is widely used as packaging materials for fragile objects during transportation because of its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high compressibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lightness</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Polystyrene has high compressibility and therefore protects delicate objects if dropped or crushed during transportation</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2014>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of converting linear alkanes to branched chain and cyclic hydrocarbons by heating in the presence of a catalyst to improve the quality of petrol is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cracking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reforming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blending</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refining</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of converting linear alkanes to branched chain and cyclic hydrocarbons by heating in the presence of a catalyst to improve the quality of petrol is referred to as reforming. Reforming is a process in the oil industry where the hydrocarbon molecules in the raw petroleum are rearranged to produce higher value molecules.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2014>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The petroleum fraction that is used in heating furnaces in industries is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gasoline</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kerosene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lubricating oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diesel oil</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diesel oil is the petroleum fraction that is used in heating furnaces in industries. Diesel oil has a higher boiling point and is heavier compared to other fractions like gasoline and kerosene, making it suitable for use in heating furnaces.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}];
